import{_ as n,o as a,c as p,ak as l}from"./chunks/framework.DwHlt8HN.js";const T=JSON.parse('{"title":"计算机网络","description":"","frontmatter":{},"headers":[],"relativePath":"cs/network/index.md","filePath":"cs/network/index.md","lastUpdated":1774320699000}'),e={name:"cs/network/index.md"};function i(r,s,t,c,o,b){return a(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="计算机网络" tabindex="-1">计算机网络 <a class="header-anchor" href="#计算机网络" aria-label="Permalink to “计算机网络”">​</a></h1><p>连接世界的隐形桥梁，每一个「打开网页」背后的技术真相。</p><p>你每天都在用计算机网络——打开网页、发送消息、在线支付、看视频。但有多少人真正理解这个过程是怎么发生的？输入一个 URL 到页面展示，中间经历了哪些步骤？TCP 的三次握手为什么是三次而不是两次？HTTPS 是怎么做到加密传输的？HTTP/2 和 HTTP/3 改进了什么？</p><p>计算机网络不是「背概念」的学科，它是理解互联网运作方式的底层能力。无论是排查网络故障、分析性能瓶颈，还是设计高并发系统，都离不开扎实的网络基础。</p><p>这篇文章系列覆盖七层网络模型、TCP/UDP 协议、HTTP/HTTPS/WebSocket、TCP 连接管理（滑动窗口、拥塞控制）、DNS、CDN、以及常考的网络编程问题，从原理到实战帮你构建完整的网络知识体系。</p><h2 id="模块速览" tabindex="-1">模块速览 <a class="header-anchor" href="#模块速览" aria-label="Permalink to “模块速览”">​</a></h2><p>计算机网络的知识点可以划分为「协议栈视角」和「问题视角」两条主线。前者帮你建立全局认知，后者帮你应对面试。</p><table tabindex="0"><thead><tr><th>方向</th><th>核心内容</th></tr></thead><tbody><tr><td><strong>网络基础</strong></td><td>OSI 七层模型、TCP/IP 四层模型、各层职责与设备</td></tr><tr><td><strong>传输层</strong></td><td>TCP 三次握手/四次挥手、滑动窗口、拥塞控制、UDP 特性</td></tr><tr><td><strong>应用层</strong></td><td>HTTP/HTTPS/WebSocket、DNS 解析、CDN 原理</td></tr><tr><td><strong>网络编程</strong></td><td>Socket 编程、BIO/NIO/AIO、多路复用（select/poll/epoll）</td></tr><tr><td><strong>高频面试</strong></td><td>URL 到页面展示的过程、HTTPS 加密过程、TCP vs UDP 选型</td></tr></tbody></table><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to “学习路径建议”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第一阶段：建立全局认知（2-3 天）</span></span>
<span class="line"><span>→ 理解 OSI 七层模型和 TCP/IP 四层模型</span></span>
<span class="line"><span>→ 各层的职责：谁负责传输、谁负责路由、谁负责加密</span></span>
<span class="line"><span>→ 理解「封装」和「分用」的过程</span></span>
<span class="line"><span>→ 常见面试题：五层/七层模型分别是什么？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二阶段：传输层深入（1 周）</span></span>
<span class="line"><span>→ TCP 三次握手：为什么需要三次？SYN/ACK 的序号怎么定？</span></span>
<span class="line"><span>→ TCP 四次挥手：为什么 TIME_WAIT 是 2MSL？大量 CLOSE_WAIT 是什么原因？</span></span>
<span class="line"><span>→ 滑动窗口：流量控制是怎么实现的？</span></span>
<span class="line"><span>→ 拥塞控制：慢启动、拥塞避免、快速重传、快速恢复</span></span>
<span class="line"><span>→ UDP：为什么 DNS 查询用 UDP？什么时候选 UDP？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三阶段：应用层协议（1 周）</span></span>
<span class="line"><span>→ HTTP 发展史：1.0 → 1.1 → 2.0 → 3.0 的演进</span></span>
<span class="line"><span>→ HTTP 方法：GET/POST/PUT/DELETE，幂等性分析</span></span>
<span class="line"><span>→ 状态码：2xx/3xx/4xx/5xx 常见场景</span></span>
<span class="line"><span>→ HTTPS：SSL/TLS 握手过程，对称加密与非对称加密</span></span>
<span class="line"><span>→ DNS：解析过程、递归查询与迭代查询、TTL</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第四阶段：网络编程与综合（1 周）</span></span>
<span class="line"><span>→ Socket 通信：TCP 服务端/客户端代码编写</span></span>
<span class="line"><span>→ I/O 模型：BIO、NIO、AIO 的演进</span></span>
<span class="line"><span>→ 多路复用：select/poll/epoll 的原理与区别</span></span>
<span class="line"><span>→ 综合题：输入 URL 到页面展示的全过程</span></span>
<span class="line"><span>→ CDN 原理：就近访问、缓存策略</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br></div></div><h2 id="一个经典问题的完整解答" tabindex="-1">一个经典问题的完整解答 <a class="header-anchor" href="#一个经典问题的完整解答" aria-label="Permalink to “一个经典问题的完整解答”">​</a></h2><p>面试中最高频的网络题是：<strong>「从输入 URL 到页面展示，发生了什么？」</strong></p><p>这个问题看似简单，实则考察了计算机网络的全貌。好的回答应该涵盖：</p><p><strong>第一步：URL 解析</strong></p><ul><li>浏览器解析 URL，提取协议、域名、路径、端口</li><li>HSTS（HTTPS 严格传输安全）检查</li></ul><p><strong>第二步：DNS 解析</strong></p><ul><li>浏览器缓存 → 系统缓存 → hosts 文件 → 本地 DNS 服务器</li><li>本地 DNS 缓存未命中时，递归/迭代查询权威 DNS 服务器</li><li>DNS 负载均衡：返回不同 IP 给不同用户</li></ul><p><strong>第三步：TCP 连接（三次握手）</strong></p><ul><li>客户端发送 SYN（seq=x）</li><li>服务端返回 SYN+ACK（seq=y, ack=x+1）</li><li>客户端发送 ACK（ack=y+1）</li><li>此时双方确认彼此的发送和接收能力正常</li></ul><p><strong>第四步：TLS 握手（HTTPS）</strong></p><ul><li>客户端发送支持的 TLS 版本和加密套件列表</li><li>服务端选择加密套件，发送证书</li><li>客户端验证证书有效性（证书链、域名、有效期）</li><li>双方协商对称密钥</li></ul><p><strong>第五步：HTTP 请求</strong></p><ul><li>浏览器构造 HTTP 请求报文</li><li>GET 请求通常没有 body，POST 有 body</li></ul><p><strong>第六步：渲染</strong></p><ul><li>服务端返回 HTML/CSS/JS/图片等资源</li><li>浏览器解析 HTML，构建 DOM 树</li><li>遇到 CSS 加载 CSS，遇到 JS 阻塞渲染</li><li>构建渲染树，布局计算，绘制页面</li></ul><blockquote><p>这个问题的价值在于：它不是考察你背了哪一层，而是考察你对整个网络的融会贯通。</p></blockquote><h2 id="面试的核心逻辑" tabindex="-1">面试的核心逻辑 <a class="header-anchor" href="#面试的核心逻辑" aria-label="Permalink to “面试的核心逻辑”">​</a></h2><p>网络面试的三个核心维度：</p><p><strong>第一，协议原理。</strong> TCP 的可靠性是怎么保证的？滑动窗口和拥塞控制分别解决什么问题？HTTP/2 的多路复用是什么原理？</p><p><strong>第二，对比选型。</strong> TCP 和 UDP 的区别是什么？什么场景必须用 TCP？什么场景适合用 UDP？HTTP 和 WebSocket 各自适用什么场景？</p><p><strong>第三，问题排查。</strong> TCP 连接超时可能是什么原因？浏览器报「请求超时」怎么排查？DNS 劫持是什么原理？如何防御？</p><blockquote><p>&quot;计算机网络的面试，最怕的是『只知道概念，说不出过程』。能把『三次握手』讲到序列号和确认号的层面，才算真正理解。&quot;</p></blockquote>`,32)])])}const u=n(e,[["render",i]]);export{T as __pageData,u as default};
